--
-- Table structure for table `rams`
--

DROP TABLE IF EXISTS `rams`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `rams` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `dateks_id` int unsigned NOT NULL,
  `url` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `price` decimal(10,2) DEFAULT NULL,
  `stock_status` enum('in_stock','orderable','out_of_stock') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'out_of_stock',
  `stock_quantity` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `memory_type` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `capacity` smallint DEFAULT NULL,
  `frequency` smallint DEFAULT NULL,
  `cl_latency` tinyint DEFAULT NULL,
  `modules_count` tinyint NOT NULL DEFAULT '1',
  `scraped_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `rams_dateks_id_unique` (`dateks_id`),
  KEY `rams_memory_type_capacity_frequency_index` (`memory_type`,`capacity`,`frequency`),
  KEY `rams_capacity_modules_count_index` (`capacity`,`modules_count`),
  KEY `rams_name_index` (`name`),
  KEY `rams_price_index` (`price`),
  KEY `rams_stock_status_index` (`stock_status`),
  KEY `rams_memory_type_index` (`memory_type`),
  KEY `rams_capacity_index` (`capacity`),
  KEY `rams_frequency_index` (`frequency`),
  KEY `rams_cl_latency_index` (`cl_latency`),
  KEY `rams_modules_count_index` (`modules_count`),
  KEY `rams_scraped_at_index` (`scraped_at`)
) ENGINE=InnoDB AUTO_INCREMENT=921 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

