DROP TABLE IF EXISTS `fans`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `fans` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `dateks_id` int unsigned NOT NULL,
  `url` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `price` decimal(10,2) DEFAULT NULL,
  `stock_status` enum('in_stock','orderable','out_of_stock') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'out_of_stock',
  `stock_quantity` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `size_mm` smallint DEFAULT NULL,
  `connector` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `rpm_max` smallint DEFAULT NULL,
  `units_in_package` tinyint DEFAULT NULL,
  `scraped_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `fans_dateks_id_unique` (`dateks_id`),
  KEY `fans_size_mm_connector_index` (`size_mm`,`connector`),
  KEY `fans_name_index` (`name`),
  KEY `fans_price_index` (`price`),
  KEY `fans_stock_status_index` (`stock_status`),
  KEY `fans_size_mm_index` (`size_mm`),
  KEY `fans_connector_index` (`connector`),
  KEY `fans_rpm_max_index` (`rpm_max`),
  KEY `fans_units_in_package_index` (`units_in_package`),
  KEY `fans_scraped_at_index` (`scraped_at`)
) ENGINE=InnoDB AUTO_INCREMENT=1060 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

